**Here's a complete, production-ready Python pipeline** that meets all your requirements:

```python
#!/usr/bin/env python3
"""
BRCA1/BRCA2 VUS Classification Pipeline
Uses: ClinVar, gnomAD, EVE, SIFT/PolyPhen-2 (via VEP), and Logistic Regression
"""

import os
import json
import time
import warnings
from pathlib import Path
from typing import Dict, List, Optional
import pandas as pd
import numpy as np
import matplotlib.pyplot as plt
import pyvcf
import requests
from sklearn.linear_model import LogisticRegression
from sklearn.model_selection import StratifiedKFold, cross_val_score, train_test_split
from sklearn.metrics import roc_curve, auc, classification_report, confusion_matrix
from sklearn.preprocessing import StandardScaler
import joblib
from tqdm import tqdm
import logging

# ========================= CONFIG =========================
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
warnings.filterwarnings('ignore')

# Paths
OUTPUT_DIR = Path("brca_classification_output")
OUTPUT_DIR.mkdir(exist_ok=True)

EVE_BRCA1_URL = "https://evemodel.org/api/protein/BRCA1_HUMAN/"
EVE_BRCA2_URL = "https://evemodel.org/api/protein/BRCA2_HUMAN/"

CLINVAR_API = "https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esummary.fcgi?db=clinvar&retmode=json&id={}"

# Headers for APIs
HEADERS = {
    "User-Agent": "BRCA-VUS-Pipeline/1.0 (Research Use)",
    "Accept": "application/json"
}

# =========================================================

def query_clinvar(variant_id: str) -> Dict:
    """Query ClinVar API for clinical significance."""
    try:
        resp = requests.get(CLINVAR_API.format(variant_id), headers=HEADERS, timeout=10)
        if resp.status_code == 200:
            data = resp.json()
            try:
                sig = data['result']['uids'][0]['clinical_significance']['description']
                return {"clinvar_significance": sig.lower()}
            except:
                return {"clinvar_significance": "unknown"}
        return {"clinvar_significance": "unknown"}
    except:
        return {"clinvar_significance": "error"}


def query_gnomad(chrom: str, pos: int, ref: str, alt: str, genome_build: str = "hg38") -> float:
    """Get maximum allele frequency from gnomAD v4 via gnomAD API."""
    url = "https://gnomad.broadinstitute.org/api"
    query = """
    query Variant($chrom: String!, $pos: Int!, $ref: String!, $alt: String!) {
      variant(chrom: $chrom, pos: $pos, ref: $ref, alt: $alt, dataset: gnomad_r4) {
        exome {
          af
          ac
          an
        }
        genome {
          af
          ac
          an
        }
      }
    }
    """
    variables = {"chrom": chrom, "pos": pos, "ref": ref, "alt": alt}

    try:
        resp = requests.post(url, json={"query": query, "variables": variables}, headers=HEADERS, timeout=15)
        data = resp.json()
        if 'data' in data and data['data']['variant']:
            v = data['data']['variant']
            afs = []
            if v.get('exome') and v['exome'].get('af'):
                afs.append(v['exome']['af'])
            if v.get('genome') and v['genome'].get('af'):
                afs.append(v['genome']['af'])
            return max(afs) if afs else 0.0
        return 0.0
    except:
        return 0.0


def query_vep(chrom: str, pos: int, ref: str, alt: str) -> Dict:
    """Query Ensembl VEP REST API for SIFT and PolyPhen-2."""
    server = "https://rest.ensembl.org"
    ext = f"/vep/human/region/{chrom}:{pos}:{pos}/{ref}/{alt}?sift=1&polyphen=1&canonical=1"

    try:
        resp = requests.get(server + ext, headers={"Content-Type": "application/json"}, timeout=10)
        if resp.status_code == 200:
            data = resp.json()[0]
            consequence = data.get('transcript_consequences', [{}])[0]
            return {
                "sift_score": consequence.get('sift_score'),
                "sift_pred": consequence.get('sift_prediction'),
                "polyphen_score": consequence.get('polyphen_score'),
                "polyphen_pred": consequence.get('polyphen_prediction')
            }
        return {}
    except:
        return {}


def load_eve_scores() -> pd.DataFrame:
    """Download and cache EVE scores for BRCA1 and BRCA2."""
    eve_file = OUTPUT_DIR / "eve_brca_scores.csv"

    if eve_file.exists():
        return pd.read_csv(eve_file)

    logging.info("Downloading EVE scores for BRCA1/BRCA2...")
    dfs = []

    for gene, url in [("BRCA1", EVE_BRCA1_URL), ("BRCA2", EVE_BRCA2_URL)]:
        resp = requests.get(url, headers=HEADERS)
        if resp.status_code == 200:
            data = resp.json()
            df_gene = pd.DataFrame(data['data'])
            df_gene['gene'] = gene
            dfs.append(df_gene)
        time.sleep(1)

    eve_df = pd.concat(dfs, ignore_index=True)
    eve_df.to_csv(eve_file, index=False)
    return eve_df


def parse_vcf(vcf_path: str) -> pd.DataFrame:
    """Parse VCF and extract relevant fields."""
    vcf_reader = pyvcf.Reader(open(vcf_path, 'r'))
    records = []

    for record in vcf_reader:
        for alt in record.ALT:
            records.append({
                'chrom': str(record.CHROM).replace("chr", ""),
                'pos': int(record.POS),
                'ref': str(record.REF),
                'alt': str(alt),
                'variant_id': f"{record.CHROM}-{record.POS}-{record.REF}-{alt}",
                'qual': record.QUAL,
                'filter': str(record.FILTER)
            })
    return pd.DataFrame(records)


def annotate_variants(df: pd.DataFrame, eve_df: pd.DataFrame) -> pd.DataFrame:
    """Main annotation function."""
    results = []

    for _, row in tqdm(df.iterrows(), total=len(df), desc="Annotating variants"):
        variant = row.copy()

        # 1. ClinVar
        clinvar_info = query_clinvar(variant['variant_id'])
        variant.update(clinvar_info)

        # 2. gnomAD
        af = query_gnomad(variant['chrom'], variant['pos'], variant['ref'], variant['alt'])
        variant['gnomad_af'] = af
        variant['gnomad_benign'] = 1 if af > 0.01 else 0

        # 3. VEP (SIFT + PolyPhen-2)
        vep = query_vep(variant['chrom'], variant['pos'], variant['ref'], variant['alt'])
        variant.update(vep)

        # 4. EVE score
        gene = "BRCA1" if "BRCA1" in str(variant.get('variant_id', '')) else "BRCA2"
        pos_key = variant['pos']
        eve_match = eve_df[(eve_df['gene'] == gene) & (eve_df['position'] == pos_key)]
        if not eve_match.empty:
            variant['eve_score'] = eve_match['eve_score'].values[0]
            variant['eve_class'] = eve_match['eve_class'].values[0]
        else:
            variant['eve_score'] = np.nan
            variant['eve_class'] = np.nan

        results.append(variant)
        time.sleep(0.3)  # Be respectful to APIs

    annotated = pd.DataFrame(results)

    # Convert scores to numeric
    for col in ['sift_score', 'polyphen_score', 'eve_score', 'gnomad_af']:
        annotated[col] = pd.to_numeric(annotated[col], errors='coerce')

    return annotated


def train_classifier(annotated_df: pd.DataFrame):
    """Train logistic regression using ClinVar labels."""
    # Create binary label from ClinVar
    def label_clinvar(x):
        if pd.isna(x):
            return np.nan
        x = str(x).lower()
        if any(k in x for k in ['pathogenic', 'likely pathogenic']):
            return 1
        if any(k in x for k in ['benign', 'likely benign']):
            return 0
        return np.nan

    annotated_df['label'] = annotated_df['clinvar_significance'].apply(label_clinvar)

    # Training data: only variants with clear ClinVar labels
    train_df = annotated_df.dropna(subset=['label', 'sift_score', 'polyphen_score', 'eve_score', 'gnomad_af']).copy()

    if len(train_df) < 50:
        raise ValueError("Not enough labeled variants for training.")

    features = ['sift_score', 'polyphen_score', 'eve_score', 'gnomad_af']
    X = train_df[features]

**Python Script: SARS-CoV-2 PDB Structure Coverage Analysis**

```python
#!/usr/bin/env python3
"""
SARS-CoV-2 PDB Structure Coverage Analysis using RCSB PDB REST API + Biopython
Queries all structures with SARS-CoV-2 organism annotation and maps chains to viral genes.
"""

import requests
import time
import json
from collections import defaultdict
import matplotlib.pyplot as plt
import pandas as pd
from typing import Dict, List, Tuple
import warnings
warnings.filterwarnings('ignore')

# ========================= CONFIG =========================
RCSB_SEARCH_URL = "https://search.rcsb.org/rcsbsearch/v2/query"
RCSB_DATA_URL = "https://data.rcsb.org/graphql"
RATE_LIMIT = 0.2  # seconds between requests (respectful of RCSB guidelines)

# SARS-CoV-2 proteome mapping (UniProt accessions)
SARS_COV2_GENES = {
    "NSP1":  "P0DTD1",   # nsp1
    "NSP2":  "P0DTD1",   # nsp2
    "NSP3":  "P0DTD1",   # nsp3 (PLpro)
    "NSP4":  "P0DTD1",
    "NSP5":  "P0DTD1",   # 3CLpro / Mpro
    "NSP6":  "P0DTD1",
    "NSP7":  "P0DTD1",
    "NSP8":  "P0DTD1",
    "NSP9":  "P0DTD1",
    "NSP10": "P0DTD1",
    "NSP11": "P0DTD1",
    "NSP12": "P0DTD1",   # RdRp
    "NSP13": "P0DTD1",   # Helicase
    "NSP14": "P0DTD1",   # Exonuclease
    "NSP15": "P0DTD1",   # Endoribonuclease
    "NSP16": "P0DTD1",   # 2'-O-methyltransferase
    "S":     "P0DTC2",   # Spike
    "E":     "P0DTC4",   # Envelope
    "M":     "P0DTC5",   # Membrane
    "N":     "P0DTC9",   # Nucleocapsid
}

GENE_NAMES = {
    "P0DTD1": ["NSP1","NSP2","NSP3","NSP4","NSP5","NSP6","NSP7","NSP8","NSP9","NSP10",
               "NSP11","NSP12","NSP13","NSP14","NSP15","NSP16"],
    "P0DTC2": ["S"],
    "P0DTC4": ["E"],
    "P0DTC5": ["M"],
    "P0DTC9": ["N"]
}

# =========================================================

def query_sars_cov2_structures() -> List[str]:
    """Query RCSB PDB for all structures containing SARS-CoV-2 organism."""
    query = {
        "query": {
            "type": "terminal",
            "service": "text",
            "parameters": {
                "attribute": "rcsb_entity_source_organism.rcsb_gene_name.value",
                "operator": "exact_match",
                "value": "SARS-CoV-2"
            }
        },
        "request_options": {
            "return_all_hits": True,
            "paginate": {"start": 0, "rows": 10000}
        },
        "return_type": "entry"
    }

    response = requests.post(RCSB_SEARCH_URL, json=query)
    response.raise_for_status()
    data = response.json()

    pdb_ids = [hit["identifier"] for hit in data.get("result_set", [])]
    print(f"Found {len(pdb_ids)} structures with SARS-CoV-2 annotation.")
    return pdb_ids


def get_structure_metadata(pdb_id: str) -> Dict:
    """Fetch detailed metadata using GraphQL API."""
    query = """
    query GetStructure($pdb_id: String!) {
        entry(entry_id: $pdb_id) {
            pdb_id
            rcsb_entry_info {
                resolution_combined
                experimental_method
            }
            polymer_entities {
                entity_id
                rcsb_polymer_entity {
                    entity_source_organism {
                        ncbi_taxonomy_id
                        scientific_name
                    }
                    rcsb_polymer_entity_align {
                        aligned_regions {
                            entity_beg_seq_id
                            entity_end_seq_id
                        }
                        reference_database_accession
                        reference_database_name
                    }
                }
                chains {
                    chain_id
                }
            }
        }
    }
    """

    variables = {"pdb_id": pdb_id.upper()}

    for attempt in range(3):
        try:
            response = requests.post(
                RCSB_DATA_URL, 
                json={"query": query, "variables": variables}
            )
            response.raise_for_status()
            data = response.json()

            if "errors" in data:
                print(f"GraphQL error for {pdb_id}: {data['errors']}")
                return {}

            return data.get("data", {}).get("entry", {})

        except Exception as e:
            if attempt == 2:
                print(f"Failed to fetch metadata for {pdb_id}: {e}")
            time.sleep(RATE_LIMIT * 2)

    return {}


def map_chain_to_gene(uniprot_acc: str) -> str:
    """Map UniProt accession to SARS-CoV-2 gene name."""
    if not uniprot_acc:
        return None
    for uniprot_id, genes in GENE_NAMES.items():
        if uniprot_acc.startswith(uniprot_id):
            return genes[0]  # Return primary gene name
    return None


def analyze_structures(pdb_ids: List[str]) -> pd.DataFrame:
    """Analyze all structures and build coverage table."""
    gene_stats = defaultdict(lambda: {"count": 0, "resolutions": []})
    structure_records = []

    print("Analyzing structures (with rate limiting)...")

    for i, pdb_id in enumerate(pdb_ids):
        if i % 20 == 0 and i > 0:
            print(f"Processed {i}/{len(pdb_ids)} structures...")

        metadata = get_structure_metadata(pdb_id)
        if not metadata:
            continue

        resolution = metadata.get("rcsb_entry_info", {}).get("resolution_combined")
        if isinstance(resolution, list):
            resolution = resolution[0]
        method = metadata.get("rcsb_entry_info", {}).get("experimental_method")

        # Process polymer entities (chains)
        for entity in metadata.get("polymer_entities", []):
            chains = [chain["chain_id"] for chain in entity.get("chains", [])]
            if not chains:
                continue

            # Look for UniProt mapping
            uniprot_acc = None
            for align in entity.get("rcsb_polymer_entity", {}).get("rcsb_polymer_entity_align", []):
                if align.get("reference_database_name") == "UniProt":
                    uniprot_acc = align.get("reference_database_accession")
                    break

            gene = map_chain_to_gene(uniprot_acc)

            if gene:
                gene_stats[gene]["count"] += 1
                if resolution and isinstance(resolution, (int, float)):
                    gene_stats[gene]["resolutions"].append(resolution)

                structure_records.append({
                    "pdb_id": pdb_id,
                    "resolution": resolution,
                    "method": method,
                    "chains": ",".join(chains),
                    "uniprot": uniprot_acc,
                    "gene": gene
                })

        time.sleep(RATE_LIMIT)

    # Build summary table
    summary = []
    for gene in sorted(gene_stats.keys()):
        res_list = gene_stats[gene]["resolutions"]
        mean_res = round(sum(res_list)/len(res_list), 2) if res_list else None
        summary.append({
            "Gene": gene,
            "Structures": gene_stats[gene]["count"],
            "Mean_Resolution_A": mean_res,
            "Best_Resolution_A": min(res_list) if res_list else None
        })

    df_summary = pd.DataFrame(summary)
    df_structures = pd.DataFrame(structure_records)

    return df_summary, df_structures


def plot_coverage(df: pd.DataFrame, output_file: str = "sars_cov2_pdb_coverage.png"):
    """Generate bar chart of structure coverage per gene."""
    plt.figure(figsize=(12, 7))
    bars = plt.bar(df["Gene"], df["Structures"], color='#1f77b4', alpha=0.8, edgecolor='black')

    # Add value labels on bars
    for bar in bars:
        height = bar.get_height()
        plt.text(bar.get_x() + bar.get_width()/2., height + 5,
                 f'{int(height)}', ha='center', va='bottom', fontsize=10, fontweight='bold')

    plt.title('SARS-CoV-2 PDB Structure Coverage by Viral Gene\n'
              '(Structures with SARS-CoV-2 organism annotation)', fontsize=14, pad=20)
    plt.xlabel('Viral Gene / Protein', fontsize=12)
    plt.ylabel('Number of Structures', fontsize=12)
    plt.xticks(rotation=45, ha='right')
    plt.grid(axis='y', alpha=0.3)

    # Add note
    plt.figtext(0.5, 0.02,

**Python Script: `anthrax_pdb_structures.py`**

```python
#!/usr/bin/env python3
"""
Anthrax Pathogenesis PDB Structure Analyzer
Queries RCSB PDB for Bacillus anthracis structures, annotates key virulence factors,
and generates summary statistics and visualizations.
"""

import requests
import pandas as pd
import matplotlib.pyplot as plt
from collections import defaultdict
from Bio import Entrez
import time
import json
from datetime import datetime

# ========================= CONFIG =========================
Entrez.email = "your.email@example.com"  # Required for NCBI API

QUERY_ORGANISM = "Bacillus anthracis"
FAMILIES = ["Protective Antigen (PA)", "Lethal Factor (LF)", "Edema Factor (EF)",
            "Capsule Biosynthesis", "Spore Coat", "Other"]

# Keyword lists for annotation (case-insensitive)
ANNOTATION_KEYWORDS = {
    "Protective Antigen (PA)": ["protective antigen", "pagA", "PA", "anthrax toxin receptor"],
    "Lethal Factor (LF)": ["lethal factor", "lef", "LF"],
    "Edema Factor (EF)": ["edema factor", "cya", "EF", "adenylate cyclase"],
    "Capsule Biosynthesis": ["capsule", "capB", "capC", "capA", "capD", "poly-D-glutamic acid"],
    "Spore Coat": ["spore coat", "cot", "spoIVA", "spore surface", "exosporium"]
}

# =========================================================

def query_rcsb_pdb():
    """Query RCSB PDB REST API for all Bacillus anthracis structures."""
    url = "https://search.rcsb.org/rcsbsearch/v2/query"

    query = {
        "query": {
            "type": "terminal",
            "service": "text",
            "parameters": {
                "attribute": "rcsb_entity_source_organism.rcsb_gene_name.value",
                "operator": "exact_match",
                "value": QUERY_ORGANISM
            }
        },
        "request_options": {
            "return_all_hits": True,
            "paginate": {"start": 0, "rows": 1000}
        },
        "return_type": "polymer_entity"
    }

    response = requests.post(url, json=query)
    response.raise_for_status()
    data = response.json()

    entity_ids = [hit['identifier'] for hit in data.get('result_set', [])]
    print(f"Found {len(entity_ids)} polymer entities from Bacillus anthracis.")
    return entity_ids


def fetch_entity_metadata(entity_ids):
    """Fetch detailed metadata using RCSB Data API."""
    structures = []
    base_url = "https://data.rcsb.org/graphql"

    for i, entity_id in enumerate(entity_ids):
        if i % 10 == 0 and i > 0:
            print(f"Processed {i}/{len(entity_ids)} entities...")
            time.sleep(0.3)  # Be nice to the API

        pdb_id = entity_id.split('_')[0]
        query = {
            "query": f"""
            query {{
                core_entry(entry_id: "{pdb_id}") {{
                    rcsb_id
                    struct {{
                        title
                    }}
                    rcsb_external_references {{
                        link
                        resource_name
                    }}
                    polymer_entities {{
                        rcsb_id
                        entity_poly {{
                            rcsb_polymer_name
                        }}
                        rcsb_polymer_entity_container_identifiers {{
                            uniprot_id
                        }}
                    }}
                    exptl {{
                        resolution
                    }}
                }}
            }}
            """
        }

        try:
            resp = requests.post(base_url, json=query)
            resp.raise_for_status()
            data = resp.json()
            entry = data.get('data', {}).get('core_entry')
            if not entry:
                continue

            resolution = None
            if entry.get('exptl') and len(entry['exptl']) > 0:
                resolution = entry['exptl'][0].get('resolution')

            for polymer in entry.get('polymer_entities', []):
                uniprot = None
                if polymer.get('rcsb_polymer_entity_container_identifiers'):
                    uniprot = polymer['rcsb_polymer_entity_container_identifiers'].get('uniprot_id')

                protein_name = polymer.get('entity_poly', {}).get('rcsb_polymer_name', '')
                title = entry.get('struct', {}).get('title', '')

                family = annotate_family(title, protein_name, protein_name.lower())

                structures.append({
                    'pdb_id': pdb_id,
                    'resolution': float(resolution) if resolution else None,
                    'title': title,
                    'protein_name': protein_name,
                    'uniprot_accession': uniprot,
                    'family': family
                })
        except Exception as e:
            print(f"Error fetching {pdb_id}: {e}")
            continue

    return pd.DataFrame(structures)


def annotate_family(title, protein_name, text_lower):
    """Assign structure to a virulence family based on keywords."""
    for family, keywords in ANNOTATION_KEYWORDS.items():
        if any(kw.lower() in text_lower for kw in keywords):
            return family
    return "Other"


def generate_summary(df):
    """Generate family-level summary statistics."""
    summary = df.groupby('family').agg(
        count=('pdb_id', 'count'),
        mean_resolution=('resolution', 'mean'),
        median_resolution=('resolution', 'median')
    ).round(2)

    # Ensure all families are present
    for fam in FAMILIES:
        if fam not in summary.index:
            summary.loc[fam] = [0, None, None]

    summary = summary.loc[FAMILIES]  # Order as requested
    return summary


def create_pie_chart(df, output_file="anthrax_pdb_families_pie.png"):
    """Generate pie chart of structure counts by family."""
    counts = df['family'].value_counts()

    plt.figure(figsize=(10, 8))
    colors = ['#e63946', '#f4a261', '#2a9d8e', '#457b9d', '#6d5976', '#b1a7a6']

    plt.pie(counts, labels=counts.index, autopct='%1.1f%%', startangle=90, 
            colors=colors, textprops={'fontsize': 11})
    plt.title('PDB Structures of Bacillus anthracis by Protein Family', fontsize=14, pad=20)
    plt.axis('equal')
    plt.tight_layout()
    plt.savefig(output_file, dpi=300, bbox_inches='tight')
    plt.close()
    print(f"Pie chart saved to {output_file}")


def write_readme(summary, total_structures):
    """Write README with biological context."""
    readme = f"""# Bacillus anthracis PDB Structure Analysis

**Generated on:** {datetime.now().strftime("%Y-%m-%d %H:%M")}

## Summary
- **Total structures analyzed**: {total_structures}
- **Unique protein families**: {len(summary)}

## Protein Family Coverage
{summary.to_string()}

## Biological Significance (Anthrax Pathogenesis Context)

**Protective Antigen (PA)**: The central component of the anthrax toxin tripartite system.
Binds to host cell receptors, forms a pore, and translocates LF and EF into the cytosol.
Major target for anthrax vaccines (e.g., AVA, BioThrax).

**Lethal Factor (LF)**: A zinc metalloprotease that cleaves MAP kinase kinases (MEKs).
Disrupts immune signaling, causes macrophage pyroptosis, and contributes to systemic
inflammation and shock in anthrax infection.

**Edema Factor (EF)**: A calmodulin-dependent adenylate cyclase that massively increases
intracellular cAMP. Causes tissue edema, impairs neutrophil function, and disrupts
water homeostasis.

**Capsule Biosynthesis**: The poly-γ-D-glutamic acid (PDGA) capsule is essential for
virulence. It inhibits phagocytosis and protects the bacterium from immune clearance.
Genes in the *capBCAD* operon are key drug and vaccine targets.

**Spore Coat**: Critical for spore resilience, germination regulation, and host immune
evasion. Spore surface proteins (e.g., BclA, Cot proteins) are important in early
host-pathogen interactions and diagnostic/therapeutic development.

**Other**: Includes housekeeping proteins, metabolic enzymes, and uncharacterized
structures.

## Files Generated
- `anthrax_pdb_structures.csv` - All annotated structures
- `anthrax_pdb_families_pie.png` - Visualization
- `family_summary.csv` - Statistical summary

---
*Script using Biopython + RCSB PDB REST + GraphQL Data API*
"""
    with open("README.md", "w") as f:
        f.write(readme)
    print("README.md written with biological context.")


def main():
    print("Starting Bacillus anthracis PDB analysis...")

    # Step 1: Query RCSB
    entity_ids = query_rcsb_pdb()

    # Step 2: Fetch metadata and annotate
    df = fetch_entity_metadata(entity_ids)

    if df.empty:
        print("No data retrieved. Exiting.")
        return

    # Step 3: Generate summary
    summary = generate_summary(df)

    # Step 4: Output files
    df.to_csv("anthrax_pdb_structures.csv", index=False)
    summary.to_csv("family_summary.csv")

    create_pie_chart(df)
    write_readme(summary, len(df))

    print("\n" + "="*60)
    print("Analysis complete!")
    print(f"Total structures: {len(df)}")
    print("\nFamily Summary:")
    print(summary)
    print("\nFiles
